class Solution {
    public int minStartingIndex(String s, String pattern) {
        int n = s.length(), m = pattern.length();
        int[] diff = new int[n + 1];
        for (int i = 0; i < n; i++) {
            diff[i + 1] = diff[i] + (s.charAt(i) != pattern.charAt(i) ? 1 : 0);
        }
        int min = Integer.MAX_VALUE;
        for (int i = 0; i <= n - m; i++) {
            min = Math.min(min, diff[i + m] - diff[i]);
        }
        return min <= 1 ? i : -1;
    }
}
